export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(
      `${this.baseUrl}/browse?path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData }
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/delete?path=${encodeURIComponent(path)}`,
      { method: 'DELETE' }
    );
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/move`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/copy`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + await res.text());
    }
    return await res.json() as T;
  }
}

export type View = 'browse' | 'search';

export interface Route {
  view: View;
  path: string;
  query: string;
}

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

/**
 * Parse a full hash (including leading '#') into a Route.
 *
 * Browse format:  #/browse  or  #/browse/<segments>
 * Search format:  #/search?q=<query>&path=<path>
 * Anything else returns the default browse route.
 */
export function parseHash(hash: string): Route {
  if (hash.startsWith('#/browse')) {
    const afterPrefix = hash.slice('#/browse'.length); // everything after "#/browse"
    // Remove the leading '/' if present, then URL-decode what remains
    const path = afterPrefix.startsWith('/')
      ? decodeURIComponent(afterPrefix.slice(1))
      : decodeURIComponent(afterPrefix);
    return { view: 'browse', path, query: '' };
  }

  if (hash.startsWith('#/search')) {
    const queryString = hash.slice('#/search'.length);
    const params = new URLSearchParams(queryString);
    const query = params.get('q') ?? '';
    const path = params.get('path') ?? '';
    return { view: 'search', query, path };
  }

  return DEFAULT_ROUTE;
}

/**
 * Serialize a browse path into a browse hash.
 * Each segment is independently percent-encoded.
 */
export function toBrowseHash(path: string): string {
  if (path === '') {
    return '#/browse';
  }
  const segments = path.split('/');
  const encoded = segments.map((s) => encodeURIComponent(s)).join('/');
  return '#/browse/' + encoded;
}

/**
 * Serialize query and path values into a search hash.
 * Both values are percent-encoded.
 */
export function toSearchHash(query: string, path: string): string {
  return `#/search?q=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`;
}

/**
 * Read the current route from window.location.hash.
 */
export function getCurrentRoute(): Route {
  return parseHash(window.location.hash);
}

/**
 * Subscribe to hash-change events.
 * Returns an unsubscribe function.
 */
export function subscribe(callback: () => void): () => void {
  window.addEventListener('hashchange', callback);
  return () => {
    window.removeEventListener('hashchange', callback);
  };
}

/**
 * Navigate to a given hash (sets window.location.hash).
 */
export function navigate(hash: string): void {
  window.location.hash = hash;
}

/**
 * Pure formatting helpers for the file browser UI.
 *
 * Every function in this module is side-effect free (no DOM access, no network)
 * so each can be unit-tested in isolation. The module exports ONLY the six
 * functions declared here.
 */

/** Binary (1024-based) byte-unit suffixes, from bytes up to terabytes. */
const BYTE_UNITS = ["B", "KB", "MB", "GB", "TB"] as const;

/**
 * Format a byte count as a human-readable string using binary (1024-based)
 * units.
 *
 * - Values below 1024 render as an integer byte count, e.g. `0 B`, `1023 B`.
 * - Values of 1024 and above render with exactly one decimal place, keeping a
 *   trailing `.0`, e.g. `1.0 KB`, `1.5 KB`, `1.0 MB`.
 *
 * The unit caps at `TB`; values beyond 1024 TB remain expressed in terabytes.
 */
export function formatBytes(bytes: number): string {
    const units = BYTE_UNITS;
    let value = bytes;
    let unitIndex = 0;

    while (value >= 1024 && unitIndex < units.length - 1) {
        value /= 1024;
        unitIndex++;
    }

    if (unitIndex === 0) {
        // Below the KB boundary: render as an integer byte count.
        return `${Math.round(value)} ${units[unitIndex]}`;
    }

    // KB and above: one decimal place (trailing .0 preserved per spec).
    return `${value.toFixed(1)} ${units[unitIndex]}`;
}

/**
 * Normalize a relative path into a clean, slash-joined form.
 *
 * - backslashes (`\`) become forward slashes
 * - leading/trailing slashes are trimmed
 * - runs of repeated slashes collapse to one
 * - `.` and `..` segments are dropped (filtered out, NOT resolved against the
 *   parent — this also neutralizes path-traversal segments)
 * - empty/root input collapses to `""`
 */
export function normalizeRelativePath(path: string): string {
    return path
        .replace(/\\/g, "/")
        .split("/")
        .filter((segment) => segment !== "" && segment !== "." && segment !== "..")
        .join("/");
}

/**
 * Join two path fragments with a single separating slash, then normalize the
 * result (see {@link normalizeRelativePath}).
 */
export function joinPath(base: string, name: string): string {
    return normalizeRelativePath(`${base}/${name}`);
}

/**
 * Return the normalized parent relative path, or `""` when the path is already
 * at root (empty or a single segment after normalization).
 */
export function parentPath(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? "" : normalized.slice(0, lastSlash);
}

/**
 * Return the last segment of a normalized path. Returns `""` for an empty
 * path.
 */
export function basename(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
}

/** Left-pad a number to two digits with a leading zero. */
function padTwo(value: number): string {
    return String(value).padStart(2, "0");
}

/**
 * Format an ISO 8601 date string as `yyyy-MM-dd HH:mm` (local calendar time).
 *
 * Returns `""` for empty or unparseable input instead of throwing.
 */
export function formatDate(iso: string): string {
    if (!iso) {
        return "";
    }

    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) {
        return "";
    }

    const year = date.getFullYear();
    const month = padTwo(date.getMonth() + 1);
    const day = padTwo(date.getDate());
    const hours = padTwo(date.getHours());
    const minutes = padTwo(date.getMinutes());

    return `${year}-${month}-${day} ${hours}:${minutes}`;
}

